<?php // class/i18n.php - Système de traduction simple class i18n { private static $lang = 'fr'; private static $strings = []; public static function init($language = 'fr') { self::$lang = $language; self::loadLanguage($language); } private static function loadLanguage($lang) { $file = dirname(__DIR__) . "/lang/{$lang}.php"; if (file_exists($file)) { self::$strings = include $file; } } public static function t($key, $default = '') { return self::$strings[$key] ?? $default; } } // Usage: echo i18n::t('dashboard.title'); ?>